import type { Booking } from '../../types/booking';
import { cardStyle, headerStyle, statusStyle, buttonStyle } from './style.ts'

interface BookingCardProps {
  booking: Booking;
  onConfirm?: (id: number) => void;
}

export function BookingCard({ booking }: BookingCardProps) {
  return (
    <div style={cardStyle}>
      <div style={headerStyle}>
        <h3>{booking.service}</h3>
        <p><strong>ID do booking: </strong>{booking.booking_id}</p>
        <p><strong>Data: </strong> {booking.booking_dt}</p>
        <p><strong>Hor├írio: </strong> {booking.booking_hr}</p>
        <p><strong>Placa do carro: </strong>{booking.car_plate}</p>
        <p><strong>ID dos detalhes: </strong>{booking.details_id}</p>
        <p><strong>Raz├úo do agendamento: </strong>{booking.reason}</p>
        <p><strong>Servi├ºo solicitado: </strong>{booking.service}</p>
      </div>
    </div>
  );
}

import DatePicker from "react-datepicker"
import "react-datepicker/dist/react-datepicker.css"
import { useEffect, useState, useMemo } from "react"
import { getUnavailableTimes } from "../../services/booking_service"

type Props = {
  formData: any
  setFormData: any
  onBack: () => void
}


export function BookingStep({formData, setFormData, onBack}: Props) {

  function handleSubmit(){

    if (!formData.service) {
      alert("Selecione o Servi├ºo!")
      return
    }

    if (!formData.reason) {
      alert("Selecione o motivo do agendamento!")
      return
    }

    if (!formData.booking_dt) {
      alert("Selecione a data do agendamento!")
      return
    }

    if (!formData.booking_dt) {
      alert("Selecione o hor├írio do agendamento!")
      return
    }

  console.log(formData)
  } 

  const [selectedDate, setSelectedDate] = useState<Date | null>(null)
  const [selectedTime, setSelectedTime] = useState<Date | null>(null)

  const [blockedDates, setBlockedDates] = useState({
    Martelinho: [],
    Pintura: []
  })

  useEffect(() => {
  if (!formData.service || formData.reason !== "Reparo") {
    setBlockedDates({
      Martelinho: [],
      Pintura: []
    })
    return
  }

  async function fetchBlockedDates() {
    try {
      const response = await fetch(
        `http://localhost:8000/bookings/invalid_repair_days?service=${formData.service}`
      ) 

      const data = await response.json()

      setBlockedDates(data)
    } catch (error) {
      console.error("Erro ao buscar datas bloqueadas:", error)
    }
  }

  fetchBlockedDates()
}, [formData.service])

  const martelinhoBlocked = useMemo(() => {
    return blockedDates.Martelinho.map(
      (date: string) => new Date(date + "T00:00:00")
    )
  }, [blockedDates])

  const pinturaIntervals = useMemo(() => {
    return blockedDates.Pintura.map((range: string[]) => {
      const monday = new Date(range[0])
      const friday = new Date(range[1])

      return { start: monday, end: friday}
    })
  }, [blockedDates])

  const timeInterval = useMemo(() => {
    if (formData.reason === "Or├ºamento") return 15
    if (formData.reason === "Reparo") return 30
    if (formData.reason === "Retorno") return 30

    return 30 // fallback padr├úo
  }, [formData.reason])

  const [blockedTimeRanges, setBlockedTimes] = useState<string[][]>([])

  useEffect(() => {
    if (!formData.booking_dt) return

    async function fetchTimes() {
      try {
        const data = await getUnavailableTimes(formData.booking_dt)

        setBlockedTimes(data)
      } catch (error) {
        console.error(error)
      }
    }

    fetchTimes()
  }, [formData.booking_dt])

  const blockedRangesFormatted = useMemo(() => {
    if (!selectedDate) return []

    return blockedTimeRanges.map(([start, end]) => {
      const [sh, sm] = start.split(":").map(Number)
      const [eh, em] = end.split(":").map(Number)

      const startDate = new Date(selectedDate)
      startDate.setHours(sh, sm, 0)

      const endDate = new Date(selectedDate)
      endDate.setHours(eh, em, 0)

      return { start: startDate, end: endDate }
    })
  }, [blockedTimeRanges, selectedDate])

  const filterTime = (time: Date) => {
    const timeMinutes = time.getHours() * 60 + time.getMinutes()

    for (const range of blockedRangesFormatted) {
      const startMinutes = range.start.getHours() * 60 + range.start.getMinutes()

      const endMinutes = range.end.getHours() * 60 + range.end.getMinutes()

      if (timeMinutes >= startMinutes && timeMinutes <= endMinutes) {
        return false 
      }
    }
    return true
  }

  useEffect(() => {
    setSelectedDate(null)

    setFormData({
      ...formData,
      booking_dt: ""
    })
  }, [formData.reason])

  const generateAvailableTimes = () => {
    const times: Date[] = []

    const start = new Date()
    start.setHours(8, 30, 0)

    const end = new Date()
    end.setHours(17, 0, 0)

    while (start <= end) {
      times.push(new Date(start))
      start.setMinutes(start.getMinutes() + timeInterval)
    }

    return times
  }

  const availableTimes = useMemo(() => {
    return generateAvailableTimes()
  }, [timeInterval])

  return(
    <div>

        <strong>Selecione o motivo do agendamento</strong>
        <button
            type="button"
            onClick={() => setFormData({ ...formData, reason: "Or├ºamento" })}
        >
            Or├ºamento
        </button>

        <button
            type="button"
            onClick={() => setFormData({ ...formData, reason: "Reparo" })}
        >
            Reparo
        </button>

        <button
            type="button"
            onClick={() => setFormData({ ...formData, reason: "Retorno" })}
        >
            Retorno
        </button>

        <strong>Selecione o servi├ºo desejado</strong>
        <button
            type="button"
            onClick={() => setFormData({ ...formData, service: "Martelinho de ouro" })}
        >
            Martelinho de Ouro
        </button>

        <button
            type="button"
            onClick={() => setFormData({ ...formData, service: "Pintura e(ou) Funilaria" })}
        >
            Pintura e(ou) Funilaria
        </button>

        <div>
          <DatePicker
            selected={selectedDate}
            onChange={(date: Date | null) => {
              setSelectedDate(date)

              setFormData({
                ...formData,
                booking_dt: date?.toISOString().split("T")[0] || ""
              })
            }}
            dateFormat="dd/MM/yyyy"
            placeholderText="Selecione a data"
            minDate={new Date()}
            filterDate={(date: Date) => date.getDay() !== 0 && date.getDay() !== 6}
            excludeDates={formData.service === "Martelinho de ouro" && formData.reason === "Reparo" ? martelinhoBlocked : [] }
            excludeDateIntervals={formData.service === "Pintura e(ou) Funilaria" && formData.reason === "Reparo" ? pinturaIntervals : []}
          />

         <DatePicker
            selected={selectedTime}
            onChange={(time: Date | null) => {
              setSelectedTime(time)

              setFormData({
                ...formData,
                booking_hr: time
                  ? time.toTimeString().slice(0, 5)
                  : ""
              })
            }}
            showTimeSelect
            showTimeSelectOnly
            timeIntervals={timeInterval}
            timeCaption="Hor├írio"
            dateFormat="HH:mm"
            filterTime={filterTime}
            includeTimes={availableTimes}
          />
        </div>

        <button type="button" onClick={onBack}>
        Voltar
        </button>

        <button type="button" onClick={handleSubmit} 
        disabled={!formData.booking_dt || !formData.booking_hr || !formData.service || !formData.reason}>
          Finalizar Agendamento
        </button>
        

    </div>
  )}

import Select from "react-select"
import { useEffect, useState } from "react"
import { getBrands } from "../../services/brand_service"
import { customStyles } from "./style"
import { getDetailsByPlate } from "../../services/car_details_service"

type Props = {
  formData: any
  setFormData: any
  onNext: () => void
  onBack: () => void
}

type BrandOption = {
  value: number
  label: string
}

type Brand = {
  brand_id: number
  brand_name: string
}

export function CarStep({formData, setFormData, onNext, onBack}: Props) {

  function handleNext() {
    if (!formData.car_model) {
      alert("Digite o modelo do ve├¡culo!")
      return
    }

    if (!formData.car_plate) {
      alert("Digite a placa do carro!")
      return
    }

    onNext()
  }


    const [brands, setBrands] = useState<BrandOption[]>([])

    useEffect(() => {
        getBrands().then(data => {
          
          const formatted = data.map((brand: Brand) => ({
            value: brand.brand_id,
            label: brand.brand_name
        }))

        setBrands(formatted)
        })
    }, [])

  const [autoFilled, setAutoFilled] = useState(false)

  useEffect(() => {
    if (formData.car_plate?.length !== 7) return

    async function fetchVehicle() {
        const response = await getDetailsByPlate(formData.car_plate)

        if (response){setFormData((prev: any) => ({
          ...prev,
          car_model: response.car_model,
          car_color: response.car_color,
          car_year: response.car_year,
          brand_id: response.brand_id
        }))
        setAutoFilled(true)
      } else {
        setAutoFilled(false)
      }
    } 
    fetchVehicle()
}, [formData.car_plate])

  useEffect(() => {
    if (formData.car_plate.length !== 7) return

    const timeout = setTimeout(() => {
      getDetailsByPlate(formData.car_plate)
    }, 500) // 500ms debounce

    return () => clearTimeout(timeout)
  }, [formData.car_plate])

  return (
    <div>
        <input
        placeholder="Placa do carro"
        maxLength={7}
        value={formData.car_plate}
        onChange={(e) => {
          const value = e.target.value
          .toUpperCase()
          .replace(/[^A-Z0-9]/g, "")
          .slice(0, 7)
          setFormData({ ...formData, car_plate: value })

          if (value.length === 0 && autoFilled){
            setFormData({
              ...formData, 
              car_plate: "",
              car_color: "",
              car_year: "",
              brand_id: null,
              car_model: ""})

            setAutoFilled(false)
          }
        }}
        />

       <Select
        styles={customStyles}
        options={brands}
        placeholder="Selecione a marca"
        value={brands.find(b => b.value === formData.brand_id) || null}
        isDisabled={autoFilled}
        onChange={(selected: BrandOption | null) =>
        setFormData({
          ...formData,
          brand_id: selected ? selected.value: null
         })
        }
        />

        <input
        placeholder="Modelo do carro"
        value={formData.car_model}
        disabled={autoFilled}
        onChange={(e) =>
          setFormData({ ...formData, car_model: e.target.value })
        }
        />

        <input
        placeholder="Cor do carro"
        value={formData.car_color}
        onChange={(e) =>
          setFormData({ ...formData, car_color: e.target.value })
        }
        />

        <input
        placeholder="Ano do carro"
        value={formData.car_year}
        onChange={(e) =>
          setFormData({ ...formData, car_year: e.target.value })
        }
        />



        <button type="button" onClick={handleNext} disabled={!formData.car_plate || !formData.car_model}>
          Pr├│ximo
        </button>

        <button type="button" onClick={onBack}>
          Voltar
        </button>
    </div>
  )}

import { useState, useMemo, useEffect } from "react"

type Props = {
  formData: any
  setFormData: any
  onNext: () => void
}




export function CustomerStep({ formData, setFormData, onNext }: Props) {

  function handleNext() {
    if (!formData.customer_name) {
      alert("Digite o nome do cliente!")
      return
    }

    if (!formData.phone_number) {
      alert("Digite o telefone!")
      return
    }

      onNext()
  }

  function formatPhone(value: string){
    const numbers = value.replace(/\D/g, "")

    if (numbers.length <= 2) {
      return numbers
    }

    if(numbers.length <= 7){
      return `(${numbers.slice(0, 2)}) ${numbers.slice(2)}`
    }

    return `(${numbers.slice(0,2)}) ${numbers.slice(2, 7)}-${numbers.slice(7,11)}`

  }

  const [phoneDisplay, setPhoneDisplay] = useState("")

  const isStepValid = useMemo(() => {
    return (
      formData.customer_name?.trim() !== "" &&
      formData.phone_number?.length === 11
    )
  }, [formData.customer_name, formData.phone_number])

  useEffect(() => {
  if (formData.phone_number) {
    setPhoneDisplay(formatPhone(formData.phone_number))
  }
  }, [formData.phone_number])

  return (
    <div>

      <input
        placeholder="Nome do cliente"
        value={formData.customer_name}
        onChange={(e) =>
          setFormData({ ...formData, customer_name: e.target.value })
        }
      />

      <input
        placeholder="Telefone"
        value={phoneDisplay}
        onChange={(e) => {
          const raw = e.target.value.replace(/\D/g, "").slice(0, 11)

          setPhoneDisplay(formatPhone(raw))

          setFormData({...formData, phone_number: raw})
        }}
      />

      <button type="button" onClick={handleNext} disabled={!isStepValid}>
        Pr├│ximo
      </button>

    </div>
  )
}

export const customStyles = {
  control: (provided: any) => ({
    ...provided,
    color: "black"
  }),
  singleValue: (provided: any) => ({
    ...provided,
    color: "black"
  }),
  placeholder: (provided: any) => ({
    ...provided,
    color: "black"
  }),
  option: (provided: any) => ({
    ...provided,
    color: "#000"
  })
}

